use strict;
use warnings;

my $file = "/workspace/buz_inventory_delivery_report/report/delivery_report_template.xml";
open(my $fh, "<", $file) or die "Cannot open: $!";
my $content = do { local $/; <$fh> };
close($fh);

# 1. Fix <style> tag - put it on its own line with proper spacing
$content =~ s/(<style>)\s*\@font-face/\1\n                            \@font-face/;

# 2. Remove the duplicate 5th @font-face block (the last one)
# The last block is the duplicate BoldItalic one
my $duplicate_pattern = qr{
    (                            \@font-face\s*\{[^{}]*font-style:\s*italic;\s*\})\s*
    (                            \@font-face\s*\{[^{}]*font-style:\s*italic;\s*\})  # This is the duplicate
    (?=\s*\n\s*@page)
}xs;

if ($content =~ /$duplicate_pattern/) {
    # Keep the first BoldItalic, remove the second
    $content =~ s/(\@font-face\s*\{[^}]*BoldItalic[^}]*font-style:\s*italic;\s*\})\s*(\@font-face\s*\{[^}]*BoldItalic[^}]*font-style:\s*italic;\s*\})/$1/;
    print "Removed duplicate BoldItalic \@font-face block\n";
}

# 3. Make sure all @font-face blocks have consistent 28-space indentation
$content =~ s/^\s{24,32}\@font-face/                            \@font-face/gm;

# Write back
open(my $out, ">", $file) or die "Cannot write: $!";
print $out $content;
close($out);

print "Done!\n";
'

